import { clsx, type ClassValue } from "clsx"
import { twMerge } from "tailwind-merge"

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}

import { useCallback, useState } from 'react';
import { toast } from 'sonner';
import { C } from '@/lib/theme';
import { AGENTS } from '@/lib/agents';
import { humanizeError } from '@/lib/humanizeError';
import { removeTaskWithUndo } from '@/lib/undoableActions';
import { useTaskStore, type ToolName } from '@/stores/taskStore';
import { useTaskDispatch } from '@/hooks/useTaskDispatch';
import { useConfirmDialog } from '@/components/shared/ConfirmDialog';
import { commands } from '@/bindings';
import type { FileDiff } from '@/bindings';
import type { TaskDisplayData } from './TaskHeader';
import { InlineDiffView } from './DiffViewer';

/* ── Constants ─────────────────────────────────────────── */

const REASSIGN_OPTIONS: ToolName[] = ['claude', 'gemini', 'codex'];

/* ── Types ─────────────────────────────────────────────── */

interface TaskActionsProps {
  taskId: string;
  display: TaskDisplayData;
  projectDir: string | null;
  isGitRepo: boolean | null;
  onClose: () => void;
}

/* ── Component ─────────────────────────────────────────── */

export function TaskActions({ taskId, display, projectDir, isGitRepo, onClose }: TaskActionsProps) {
  const task = useTaskStore((s) => s.tasks.get(taskId));
  const updateTaskAgent = useTaskStore((s) => s.updateTaskAgent);
  const updateTaskStatus = useTaskStore((s) => s.updateTaskStatus);
  const { dispatchTask } = useTaskDispatch();
  const { confirm, ConfirmDialogElement } = useConfirmDialog();
  const [reassignOpen, setReassignOpen] = useState(false);
  const [merging, setMerging] = useState(false);
  const [mergeError, setMergeError] = useState<string | null>(null);
  const [mergeSuccess, setMergeSuccess] = useState(false);
  const [diffFiles, setDiffFiles] = useState<FileDiff[] | null>(null);
  const [diffLoading, setDiffLoading] = useState(false);
  const [diffError, setDiffError] = useState<string | null>(null);
  const [retrying, setRetrying] = useState(false);
  const [cancelling, setCancelling] = useState(false);

  const handleReassign = useCallback((newAgent: ToolName) => {
    setReassignOpen(false);
    updateTaskAgent(taskId, newAgent);
    useTaskStore.getState().addOrchestrationLog({
      agent: newAgent,
      level: 'info',
      message: `Task ${taskId.slice(0, 6)} reassigned to ${AGENTS[newAgent].label}`,
    });
  }, [taskId, updateTaskAgent]);

  const handleMerge = useCallback(async () => {
    if (!projectDir || !display) return;
    const ok = await confirm({
      title: 'Merge Branch',
      description: `Merge branch "${display.displayBranch}" into main? This cannot be undone.`,
      confirmLabel: 'Merge',
      destructive: false,
    });
    if (!ok) return;
    setMerging(true);
    setMergeError(null);
    try {
      const result = await commands.mergeWorktree(projectDir, display.branch, null);
      if (result.status === 'ok') {
        setMergeSuccess(true);
        updateTaskStatus(taskId, 'completed' as any);
        useTaskStore.getState().addOrchestrationLog({
          agent: display.agent,
          level: 'success',
          message: `Branch ${display.displayBranch} merged into main`,
        });
        toast.success('Branch merged successfully');
      } else {
        setMergeError(result.error);
        toast.error('Merge failed');
      }
    } catch (e) {
      setMergeError(String(e));
      toast.error('Merge failed');
    } finally {
      setMerging(false);
    }
  }, [projectDir, display, taskId, updateTaskStatus, confirm]);

  const handleViewChanges = useCallback(async () => {
    if (!projectDir || !display) return;
    if (diffFiles) {
      setDiffFiles(null);
      return;
    }
    setDiffLoading(true);
    setDiffError(null);
    try {
      const result = await commands.getWorktreeDiff(projectDir, display.branch);
      if (result.status === 'ok') {
        setDiffFiles(result.data.files);
      } else {
        setDiffError(result.error);
      }
    } catch (e) {
      setDiffError(String(e));
    } finally {
      setDiffLoading(false);
    }
  }, [projectDir, display, diffFiles]);

  const handleRetry = useCallback(async () => {
    if (!projectDir || !task || retrying) return;
    const ok = await confirm({
      title: 'Retry Task',
      description: `Retry this task with ${AGENTS[task.toolName].label}? The failed task will be removed.`,
      confirmLabel: 'Retry',
      destructive: true,
    });
    if (!ok) return;
    setRetrying(true);
    try {
      useTaskStore.getState().addOrchestrationLog({
        agent: task.toolName,
        level: 'info',
        message: `Retrying: ${task.description}`,
      });
      // Dispatch new task first — only remove old one on success
      const newTaskId = await dispatchTask(task.prompt, projectDir, task.toolName);

      if (newTaskId) {
        // Remove old failed task with undo support
        removeTaskWithUndo(taskId, task.description);

        // Mark retried task as worker
        const ts = useTaskStore.getState();
        const newTask = ts.tasks.get(newTaskId);
        if (newTask) {
          const newTasks = new Map(ts.tasks);
          newTasks.set(newTask.taskId, { ...newTask, role: 'worker' });
          useTaskStore.setState({ tasks: newTasks });
        }
      }
      toast.success('Task retried');
      onClose();
    } catch (e) {
      console.error('Retry failed:', e);
      toast.error('Retry failed');
      useTaskStore.getState().addOrchestrationLog({
        agent: task.toolName,
        level: 'error',
        message: `Retry failed: ${e}`,
      });
    } finally {
      setRetrying(false);
    }
  }, [projectDir, task, taskId, retrying, dispatchTask, onClose, confirm]);

  const handleCancel = useCallback(async () => {
    if (!task || cancelling) return;
    const ok = await confirm({
      title: 'Cancel Task',
      description: `Cancel the running task "${task.description}"? The agent process will be terminated.`,
      confirmLabel: 'Cancel Task',
      destructive: true,
    });
    if (!ok) return;
    setCancelling(true);
    try {
      const result = await commands.cancelProcess(task.taskId);
      if (result.status === 'ok') {
        updateTaskStatus(taskId, 'failed' as any);
        useTaskStore.getState().addOrchestrationLog({
          agent: task.toolName,
          level: 'warn',
          message: `Task cancelled by user: ${task.description}`,
        });
        toast.success('Task cancelled');
      } else {
        toast.error('Failed to cancel task', { description: humanizeError(result.error) });
      }
    } catch (e) {
      toast.error('Failed to cancel task', { description: humanizeError(e) });
    } finally {
      setCancelling(false);
    }
  }, [task, taskId, cancelling, updateTaskStatus, confirm]);

  const progress = display.isRunning && display.startedAt
    ? Math.min(95, Math.floor(((Date.now() - display.startedAt) / 120_000) * 100))
    : null;

  return (
    <>
      {ConfirmDialogElement}

      {/* Cancel card — only show for running tasks */}
      {display.isRunning && (
        <div
          style={{
            padding: 16,
            borderRadius: 14,
            background: C.amberBg,
            border: `1px solid ${C.amberBorder}`,
          }}
        >
          <div
            style={{
              fontSize: 13,
              fontWeight: 600,
              color: C.amber,
              marginBottom: 8,
            }}
          >
            Task Running
          </div>
          <p
            style={{
              fontSize: 12,
              color: C.textSecondary,
              margin: 0,
              marginBottom: 14,
              lineHeight: '18px',
            }}
          >
            This task is currently being processed. You can cancel it to stop the agent.
          </p>
          <button
            type="button"
            disabled={cancelling}
            onClick={handleCancel}
            style={{
              padding: '8px 20px',
              borderRadius: 10,
              background: cancelling ? C.borderStrong : C.red,
              border: 'none',
              color: '#fff',
              fontSize: 13,
              fontWeight: 700,
              cursor: cancelling ? 'wait' : 'pointer',
              fontFamily: 'Inter, sans-serif',
              transition: 'all 150ms ease',
              opacity: cancelling ? 0.7 : 1,
              display: 'flex',
              alignItems: 'center',
              gap: 6,
            }}
            onMouseEnter={(e) => {
              if (!cancelling) e.currentTarget.style.filter = 'brightness(1.15)';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.filter = 'brightness(1)';
            }}
          >
            {cancelling ? 'Cancelling...' : '✕ Cancel Task'}
          </button>
        </div>
      )}

      {/* Retry card — only show for failed tasks */}
      {display.status === 'failed' && projectDir && (
        <div
          style={{
            padding: 16,
            borderRadius: 14,
            background: C.redBg,
            border: `1px solid rgba(239,68,68,0.3)`,
          }}
        >
          <div
            style={{
              fontSize: 13,
              fontWeight: 600,
              color: '#f87171',
              marginBottom: 8,
            }}
          >
            Task Failed
          </div>
          <p
            style={{
              fontSize: 12,
              color: C.textSecondary,
              margin: 0,
              marginBottom: 14,
              lineHeight: '18px',
            }}
          >
            This task failed. You can retry with the same agent or reassign to a different one below.
          </p>
          <button
            type="button"
            disabled={retrying}
            onClick={handleRetry}
            style={{
              padding: '8px 20px',
              borderRadius: 10,
              background: retrying ? C.borderStrong : '#ef4444',
              border: 'none',
              color: '#fff',
              fontSize: 13,
              fontWeight: 700,
              cursor: retrying ? 'wait' : 'pointer',
              fontFamily: 'Inter, sans-serif',
              transition: 'all 150ms ease',
              opacity: retrying ? 0.7 : 1,
              display: 'flex',
              alignItems: 'center',
              gap: 6,
            }}
            onMouseEnter={(e) => {
              if (!retrying) e.currentTarget.style.filter = 'brightness(1.15)';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.filter = 'brightness(1)';
            }}
          >
            {retrying ? 'Retrying...' : '\u21BB Retry Task'}
          </button>
        </div>
      )}

      {/* Branch — only show if project is a git repo */}
      {isGitRepo && (
        <div
          style={{
            padding: '10px 14px',
            borderRadius: 12,
            background: C.surface,
            border: `1px solid ${C.border}`,
          }}
        >
          <div
            style={{
              fontSize: 10,
              fontWeight: 700,
              color: C.textMuted,
              textTransform: 'uppercase',
              letterSpacing: '0.06em',
              marginBottom: 6,
            }}
          >
            Branch
          </div>
          <div
            style={{
              fontSize: 12,
              fontFamily: 'var(--font-mono)',
              color: C.accentText,
            }}
          >
            {display.displayBranch}
          </div>
        </div>
      )}

      {/* Progress bar (if running) */}
      {progress !== null && (
        <div>
          <div
            style={{
              display: 'flex',
              justifyContent: 'space-between',
              fontSize: 11,
              color: C.textSecondary,
              marginBottom: 6,
            }}
          >
            <span>Progress</span>
            <span>{progress}%</span>
          </div>
          <div
            style={{
              width: '100%',
              height: 6,
              borderRadius: 3,
              background: C.border,
              overflow: 'hidden',
            }}
          >
            <div
              style={{
                width: `${progress}%`,
                height: '100%',
                borderRadius: 3,
                background: C.amber,
                transition: 'width 300ms ease',
              }}
            />
          </div>
        </div>
      )}

      {/* View Changes button (when done or running, and project is a git repo) */}
      {(display.isDone || display.isRunning) && projectDir && isGitRepo && (
        <div>
          <button
            type="button"
            onClick={handleViewChanges}
            disabled={diffLoading}
            style={{
              width: '100%',
              padding: '10px 14px',
              borderRadius: 12,
              background: C.surface,
              border: `1px solid ${C.border}`,
              color: C.accentText,
              fontSize: 12,
              fontWeight: 600,
              fontFamily: 'Inter, sans-serif',
              cursor: diffLoading ? 'wait' : 'pointer',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: 8,
              transition: 'all 150ms ease',
              opacity: diffLoading ? 0.6 : 1,
            }}
            onMouseEnter={(e) => {
              if (!diffLoading) e.currentTarget.style.borderColor = C.accent;
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.borderColor = C.border;
            }}
          >
            {diffLoading ? 'Loading diff...' : diffFiles ? 'Hide Changes' : 'View Changes'}
          </button>
          {diffError && (
            <div style={{ marginTop: 6, fontSize: 11, color: '#f87171' }}>{diffError}</div>
          )}
        </div>
      )}

      {/* Inline diff viewer */}
      {diffFiles && diffFiles.length > 0 && (
        <InlineDiffView files={diffFiles} onClose={() => setDiffFiles(null)} />
      )}
      {diffFiles && diffFiles.length === 0 && (
        <div
          style={{
            padding: 16,
            borderRadius: 14,
            background: C.surface,
            border: `1px solid ${C.border}`,
            textAlign: 'center',
            color: C.textMuted,
            fontSize: 12,
          }}
        >
          No changes detected in this branch yet.
        </div>
      )}

      {/* Awaiting merge card (if done and git repo) */}
      {display.isDone && !mergeSuccess && isGitRepo && (
        <div
          style={{
            padding: 16,
            borderRadius: 14,
            background: C.greenBg,
            border: `1px solid ${C.greenBorder}`,
          }}
        >
          <div
            style={{
              fontSize: 13,
              fontWeight: 600,
              color: C.green,
              marginBottom: 10,
            }}
          >
            Awaiting Merge
          </div>
          <p
            style={{
              fontSize: 12,
              color: C.textSecondary,
              margin: 0,
              marginBottom: 14,
              lineHeight: '18px',
            }}
          >
            This task is complete and its branch is ready to be merged into main.
          </p>
          {mergeError && (
            <p
              style={{
                fontSize: 11,
                color: '#f87171',
                margin: 0,
                marginBottom: 10,
                lineHeight: '16px',
                padding: '6px 10px',
                borderRadius: 8,
                background: 'rgba(248,113,113,0.1)',
              }}
            >
              {mergeError}
            </p>
          )}
          <button
            type="button"
            disabled={merging || !projectDir}
            onClick={handleMerge}
            style={{
              padding: '8px 20px',
              borderRadius: 10,
              background: merging ? C.borderStrong : C.green,
              border: 'none',
              color: '#052e16',
              fontSize: 13,
              fontWeight: 700,
              cursor: merging ? 'wait' : 'pointer',
              fontFamily: 'Inter, sans-serif',
              transition: 'all 150ms ease',
              opacity: merging ? 0.7 : 1,
            }}
            onMouseEnter={(e) => {
              if (!merging) e.currentTarget.style.filter = 'brightness(1.1)';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.filter = 'brightness(1)';
            }}
          >
            {merging ? 'Merging...' : 'Merge Branch'}
          </button>
        </div>
      )}

      {/* Merge success */}
      {mergeSuccess && (
        <div
          style={{
            padding: 16,
            borderRadius: 14,
            background: C.greenBg,
            border: `1px solid ${C.greenBorder}`,
            textAlign: 'center',
          }}
        >
          <div style={{ fontSize: 13, fontWeight: 600, color: C.green }}>
            Branch merged successfully
          </div>
        </div>
      )}

      {/* Reassign dropdown */}
      <div>
        <div
          style={{
            fontSize: 10,
            fontWeight: 700,
            color: C.textMuted,
            textTransform: 'uppercase',
            letterSpacing: '0.06em',
            marginBottom: 8,
          }}
        >
          Reassign Agent
        </div>
        <div style={{ position: 'relative' }}>
          <button
            type="button"
            onClick={() => setReassignOpen(!reassignOpen)}
            style={{
              width: '100%',
              padding: '10px 14px',
              borderRadius: 12,
              background: C.surface,
              border: `1px solid ${C.border}`,
              color: C.textPrimary,
              fontSize: 13,
              fontFamily: 'Inter, sans-serif',
              textAlign: 'left',
              cursor: 'pointer',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'space-between',
              transition: 'all 150ms ease',
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.borderColor = C.borderStrong;
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.borderColor = C.border;
            }}
          >
            <span>{AGENTS[display.agent].label}</span>
            <span style={{ fontSize: 10, color: C.textMuted }}>
              {reassignOpen ? '\u25B2' : '\u25BC'}
            </span>
          </button>

          {reassignOpen && (
            <div
              style={{
                position: 'absolute',
                top: '100%',
                left: 0,
                right: 0,
                marginTop: 4,
                borderRadius: 12,
                background: C.surface,
                border: `1px solid ${C.borderStrong}`,
                boxShadow: '0 12px 36px rgba(0,0,0,0.5)',
                zIndex: 10,
                overflow: 'hidden',
              }}
            >
              {REASSIGN_OPTIONS.filter((t) => t !== display.agent).map((toolName) => {
                const icon = AGENTS[toolName];
                return (
                  <button
                    key={toolName}
                    type="button"
                    onClick={() => handleReassign(toolName)}
                    style={{
                      width: '100%',
                      padding: '10px 14px',
                      display: 'flex',
                      alignItems: 'center',
                      gap: 10,
                      background: 'transparent',
                      border: 'none',
                      borderBottom: `1px solid ${C.border}`,
                      color: C.textPrimary,
                      fontSize: 13,
                      fontFamily: 'Inter, sans-serif',
                      cursor: 'pointer',
                      textAlign: 'left',
                      transition: 'background 150ms ease',
                    }}
                    onMouseEnter={(e) => {
                      e.currentTarget.style.background = C.surfaceHover;
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.background = 'transparent';
                    }}
                  >
                    <div
                      style={{
                        width: 22,
                        height: 22,
                        borderRadius: 7,
                        background: icon.gradient,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: 10,
                        fontWeight: 700,
                        color: '#fff',
                        flexShrink: 0,
                      }}
                    >
                      {icon.letter}
                    </div>
                    {AGENTS[toolName].label}
                  </button>
                );
              })}
            </div>
          )}
        </div>
      </div>
    </>
  );
}

import { useEffect, useState, useCallback, useMemo } from 'react';
import { C } from '@/lib/theme';
import { AGENTS } from '@/lib/agents';
import { ScrollArea } from '@/components/ui/scroll-area';
import { useShallow } from 'zustand/react/shallow';
import { useTaskStore, type ToolName } from '@/stores/taskStore';
import { useUIStore } from '@/stores/uiStore';
import { DiffReview } from '../../components/review/DiffReview';
import { useWorktree } from '../../hooks/useWorktree';

/* ── Types ─────────────────────────────────────────────── */

interface CodeReviewViewProps {
  onDone: () => void;
}

type WorktreeStatus = 'pending' | 'merged' | 'discarded' | 'error';

/* ── Sub-components ────────────────────────────────────── */

function StatCard({ label, value, color }: { label: string; value: number; color: string }) {
  return (
    <div
      style={{
        flex: 1,
        padding: '16px 14px',
        borderRadius: 14,
        background: C.surface,
        border: `1px solid ${C.border}`,
        textAlign: 'center',
      }}
    >
      <div style={{ fontSize: 24, fontWeight: 700, color, lineHeight: '32px' }}>{value}</div>
      <div style={{ fontSize: 11, color: C.textSecondary, marginTop: 4 }}>{label}</div>
    </div>
  );
}

function CheckIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none" style={{ flexShrink: 0 }}>
      <circle cx="8" cy="8" r="7" stroke={C.green} strokeWidth="1.5" />
      <path d="M5 8l2 2 4-4" stroke={C.green} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}

function WarningIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none" style={{ flexShrink: 0 }}>
      <path d="M8 2L14.93 14H1.07L8 2z" stroke={C.amber} strokeWidth="1.3" fill="none" />
      <line x1="8" y1="6.5" x2="8" y2="10" stroke={C.amber} strokeWidth="1.3" strokeLinecap="round" />
      <circle cx="8" cy="12" r="0.6" fill={C.amber} />
    </svg>
  );
}

function ChevronIcon({ expanded }: { expanded: boolean }) {
  return (
    <svg
      width="14"
      height="14"
      viewBox="0 0 14 14"
      fill="none"
      style={{
        flexShrink: 0,
        transform: expanded ? 'rotate(90deg)' : 'rotate(0deg)',
        transition: 'transform 150ms ease',
      }}
    >
      <path d="M5 3l4 4-4 4" stroke={C.textMuted} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}

function StatusBadge({ status }: { status: WorktreeStatus }) {
  const config = {
    pending: { label: 'Pending', bg: C.surface, color: C.textMuted, border: C.border },
    merged: { label: 'Merged', bg: C.greenBg, color: C.green, border: C.greenBorder },
    discarded: { label: 'Discarded', bg: C.surface, color: C.textMuted, border: C.border },
    error: { label: 'Error', bg: C.redBg, color: C.red, border: C.border },
  }[status];

  return (
    <span
      style={{
        fontSize: 10,
        fontWeight: 600,
        padding: '2px 8px',
        borderRadius: 6,
        background: config.bg,
        color: config.color,
        border: `1px solid ${config.border}`,
        textTransform: 'uppercase',
        letterSpacing: '0.04em',
      }}
    >
      {config.label}
    </span>
  );
}

/* ── Main Component ────────────────────────────────────── */

export function CodeReviewView({ onDone }: CodeReviewViewProps) {
  const { activePlan, orchestrationPlan, tasks, orchestrationLogs, worktreeEntries } = useTaskStore(
    useShallow((s) => ({
      activePlan: s.activePlan,
      orchestrationPlan: s.orchestrationPlan,
      tasks: s.tasks,
      orchestrationLogs: s.orchestrationLogs,
      worktreeEntries: s.worktreeEntries,
    })),
  );
  const setOrchestrationPhase = useTaskStore((s) => s.setOrchestrationPhase);

  const projectDir = useUIStore((s) => s.projectDir);
  const { mergeWorktree, cleanupWorktrees } = useWorktree(projectDir);

  // Determine master agent from config or plan
  const masterAgent: ToolName = (orchestrationPlan?.masterAgent as ToolName)
    || (activePlan?.master_agent as ToolName)
    || 'claude';
  const icon = AGENTS[masterAgent];

  // Derive stats from tasks
  const { taskArray, tasksDone, warnings, totalTasks } = useMemo(() => {
    const arr = Array.from(tasks.values());
    let done = 0, failed = 0;
    for (const t of arr) {
      if (t.status === 'completed') done++;
      else if (t.status === 'failed') failed++;
    }
    return { taskArray: arr, tasksDone: done, warnings: failed, totalTasks: arr.length };
  }, [tasks]);

  // Extract review text from orchestration logs
  const reviewLogs = orchestrationLogs.filter(
    l => l.level === 'success' || (l.level === 'info' && l.message.includes('Review complete'))
  );
  const reviewText = reviewLogs.length > 0
    ? reviewLogs.map(l => l.message).join('\n')
    : null;

  // Build task summary rows
  const taskRows = taskArray.map(t => ({
    id: t.taskId,
    description: t.description,
    agent: t.toolName,
    status: t.status,
    isOk: t.status === 'completed',
  }));

  // Per-worktree status tracking
  const [worktreeStatuses, setWorktreeStatuses] = useState<Map<string, WorktreeStatus>>(new Map());
  const [expandedWorktree, setExpandedWorktree] = useState<string | null>(null);
  const [mergeAllInProgress, setMergeAllInProgress] = useState(false);
  const [completing, setCompleting] = useState(false);

  // Initialize worktree statuses when entries arrive
  useEffect(() => {
    if (worktreeEntries.size > 0 && worktreeStatuses.size === 0) {
      const initial = new Map<string, WorktreeStatus>();
      for (const [dagId] of worktreeEntries) {
        initial.set(dagId, 'pending');
      }
      setWorktreeStatuses(initial);
    }
  }, [worktreeEntries, worktreeStatuses.size]);

  const entries = Array.from(worktreeEntries.values());
  const pendingCount = entries.filter(e => (worktreeStatuses.get(e.dagId) ?? 'pending') === 'pending').length;
  const errorCount = entries.filter(e => worktreeStatuses.get(e.dagId) === 'error').length;
  const allHandled = entries.length > 0 && pendingCount === 0 && errorCount === 0;
  const hasWorktrees = worktreeEntries.size > 0;

  const handleWorktreeClose = useCallback((dagId: string, action: 'merged' | 'discarded') => {
    setWorktreeStatuses(prev => {
      const next = new Map(prev);
      next.set(dagId, action);
      return next;
    });
    setExpandedWorktree(null);
  }, []);

  const handleMergeAll = useCallback(async () => {
    setMergeAllInProgress(true);
    try {
      const pendingEntries = entries.filter(e => worktreeStatuses.get(e.dagId) === 'pending');
      for (const entry of pendingEntries) {
        const success = await mergeWorktree(entry.branchName);
        setWorktreeStatuses(prev => {
          const next = new Map(prev);
          next.set(entry.dagId, success ? 'merged' : 'error');
          return next;
        });
      }
    } finally {
      setMergeAllInProgress(false);
    }
  }, [entries, worktreeStatuses, mergeWorktree]);

  const handleComplete = useCallback(async () => {
    setCompleting(true);
    try {
      await cleanupWorktrees();
    } catch {
      // Cleanup failure is non-fatal
    } finally {
      setOrchestrationPhase('completed');
      onDone();
    }
  }, [cleanupWorktrees, setOrchestrationPhase, onDone]);

  const handleDirectComplete = useCallback(() => {
    setOrchestrationPhase('completed');
    onDone();
  }, [setOrchestrationPhase, onDone]);

  return (
    <ScrollArea style={{ height: '100%' }}>
      <div
        style={{
          maxWidth: 720,
          padding: '32px 28px',
          fontFamily: 'Inter, sans-serif',
        }}
      >
        {/* Header — dynamic master agent */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 14, marginBottom: 24 }}>
          <div
            style={{
              width: 36,
              height: 36,
              borderRadius: 10,
              background: icon.gradient,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: 15,
              fontWeight: 700,
              color: '#fff',
              flexShrink: 0,
            }}
          >
            {icon.letter}
          </div>
          <div>
            <h2 style={{ fontSize: 20, fontWeight: 700, color: C.textPrimary, margin: 0 }}>
              Code Review
            </h2>
            <p style={{ fontSize: 12, color: C.textSecondary, marginTop: 2, marginBottom: 0 }}>
              {icon.label} has reviewed all completed work
            </p>
          </div>
        </div>

        {/* Stats grid */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 12, marginBottom: 24 }}>
          <StatCard label="Completed" value={tasksDone} color={C.green} />
          <StatCard label="Total Tasks" value={totalTasks} color={C.accentText} />
          <StatCard label="Warnings" value={warnings} color={C.amber} />
        </div>

        {/* Review summary from master agent */}
        {reviewText && (
          <div
            style={{
              padding: 16,
              borderRadius: 16,
              background: C.surface,
              border: `1px solid ${C.border}`,
              marginBottom: 24,
            }}
          >
            <div
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 8,
                marginBottom: 12,
                fontSize: 11,
                fontWeight: 700,
                color: C.textMuted,
                textTransform: 'uppercase',
                letterSpacing: '0.06em',
              }}
            >
              <div
                style={{
                  width: 18,
                  height: 18,
                  borderRadius: 5,
                  background: icon.gradient,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: 9,
                  fontWeight: 700,
                  color: '#fff',
                }}
              >
                {icon.letter}
              </div>
              {icon.label}&apos;s Review
            </div>
            <div
              style={{
                fontSize: 13,
                color: C.textPrimary,
                lineHeight: '22px',
                whiteSpace: 'pre-wrap',
                fontFamily: 'var(--font-mono)',
              }}
            >
              {reviewText}
            </div>
          </div>
        )}

        {/* Task results table */}
        {taskRows.length > 0 && (
          <div
            style={{
              borderRadius: 16,
              border: `1px solid ${C.border}`,
              overflow: 'hidden',
              marginBottom: 24,
            }}
          >
            <div
              style={{
                display: 'grid',
                gridTemplateColumns: '28px 1fr 1fr',
                gap: 12,
                padding: '10px 16px',
                background: C.surface,
                borderBottom: `1px solid ${C.border}`,
                fontSize: 11,
                fontWeight: 600,
                color: C.textMuted,
                textTransform: 'uppercase',
                letterSpacing: '0.05em',
              }}
            >
              <span />
              <span>Task</span>
              <span>Agent / Status</span>
            </div>
            {taskRows.map((row) => {
              const agentIcon = AGENTS[row.agent] ?? AGENTS.claude;
              return (
                <div
                  key={row.id}
                  style={{
                    display: 'grid',
                    gridTemplateColumns: '28px 1fr 1fr',
                    gap: 12,
                    padding: '12px 16px',
                    borderBottom: `1px solid ${C.border}`,
                    alignItems: 'center',
                  }}
                >
                  {row.isOk ? <CheckIcon /> : <WarningIcon />}
                  <span
                    style={{
                      fontSize: 12,
                      fontFamily: 'var(--font-mono)',
                      color: C.textPrimary,
                      overflow: 'hidden',
                      textOverflow: 'ellipsis',
                      whiteSpace: 'nowrap',
                    }}
                  >
                    {row.description}
                  </span>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                    <div
                      style={{
                        width: 16,
                        height: 16,
                        borderRadius: 4,
                        background: agentIcon.gradient,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: 8,
                        fontWeight: 700,
                        color: '#fff',
                        flexShrink: 0,
                      }}
                    >
                      {agentIcon.letter}
                    </div>
                    <span style={{ fontSize: 12, color: C.textSecondary, lineHeight: '18px' }}>
                      {agentIcon.label} — {row.status}
                    </span>
                  </div>
                </div>
              );
            })}
          </div>
        )}

        {/* ── Per-Worktree Review Section ────────────────── */}
        {hasWorktrees ? (
          <div style={{ marginBottom: 24 }}>
            <div
              style={{
                fontSize: 11,
                fontWeight: 700,
                color: C.textMuted,
                textTransform: 'uppercase',
                letterSpacing: '0.06em',
                marginBottom: 12,
              }}
            >
              Worktree Changes ({entries.length})
            </div>

            {entries.map((entry) => {
              const status = worktreeStatuses.get(entry.dagId) ?? 'pending';
              const isExpanded = expandedWorktree === entry.dagId;
              const isHandled = status !== 'pending';

              return (
                <div
                  key={entry.dagId}
                  style={{
                    borderRadius: 14,
                    border: `1px solid ${C.border}`,
                    marginBottom: 10,
                    overflow: 'hidden',
                    opacity: isHandled ? 0.6 : 1,
                    transition: 'opacity 150ms ease',
                  }}
                >
                  {/* Worktree card header */}
                  <button
                    type="button"
                    onClick={() => setExpandedWorktree(isExpanded ? null : entry.dagId)}
                    disabled={isHandled}
                    style={{
                      width: '100%',
                      display: 'flex',
                      alignItems: 'center',
                      gap: 10,
                      padding: '12px 16px',
                      background: C.surface,
                      border: 'none',
                      cursor: isHandled ? 'default' : 'pointer',
                      textAlign: 'left',
                      fontFamily: 'Inter, sans-serif',
                      transition: 'background 150ms ease',
                      outline: 'revert',
                    }}
                    onMouseEnter={(e) => {
                      if (!isHandled) e.currentTarget.style.background = C.surfaceHover;
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.background = C.surface;
                    }}
                  >
                    <ChevronIcon expanded={isExpanded} />
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontSize: 13, fontWeight: 600, color: C.textPrimary, marginBottom: 2 }}>
                        {entry.branchName}
                      </div>
                      <div style={{ fontSize: 11, color: C.textSecondary, display: 'flex', gap: 10 }}>
                        <span>{entry.fileCount} file{entry.fileCount !== 1 ? 's' : ''}</span>
                        <span style={{ color: C.green }}>+{entry.additions}</span>
                        <span style={{ color: '#f87171' }}>-{entry.deletions}</span>
                      </div>
                    </div>
                    <StatusBadge status={status} />
                  </button>

                  {/* Expanded diff viewer */}
                  {isExpanded && !isHandled && projectDir && (
                    <div style={{ height: 480, borderTop: `1px solid ${C.border}` }}>
                      <DiffReview
                        projectDir={projectDir}
                        branchName={entry.branchName}
                        taskId={entry.dagId}
                        onClose={(action) => handleWorktreeClose(entry.dagId, action)}
                      />
                    </div>
                  )}
                </div>
              );
            })}

            {/* Batch merge controls */}
            <div
              style={{
                display: 'flex',
                justifyContent: 'flex-end',
                gap: 10,
                marginTop: 16,
              }}
            >
              {pendingCount > 0 && (
                <button
                  type="button"
                  onClick={handleMergeAll}
                  disabled={mergeAllInProgress}
                  style={{
                    padding: '8px 20px',
                    borderRadius: 12,
                    background: icon.gradient,
                    border: 'none',
                    color: '#fff',
                    fontSize: 13,
                    fontWeight: 600,
                    cursor: mergeAllInProgress ? 'not-allowed' : 'pointer',
                    fontFamily: 'Inter, sans-serif',
                    boxShadow: '0 8px 24px rgba(109,94,252,0.28)',
                    opacity: mergeAllInProgress ? 0.6 : 1,
                    transition: 'all 150ms ease',
                  }}
                  onMouseEnter={(e) => {
                    if (!mergeAllInProgress) e.currentTarget.style.filter = 'brightness(1.1)';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.filter = 'brightness(1)';
                  }}
                >
                  {mergeAllInProgress ? 'Merging…' : `Merge All (${pendingCount})`}
                </button>
              )}

              {allHandled && (
                <button
                  type="button"
                  onClick={handleComplete}
                  disabled={completing}
                  style={{
                    padding: '8px 20px',
                    borderRadius: 12,
                    background: C.green,
                    border: 'none',
                    color: '#fff',
                    fontSize: 13,
                    fontWeight: 600,
                    cursor: completing ? 'not-allowed' : 'pointer',
                    fontFamily: 'Inter, sans-serif',
                    opacity: completing ? 0.6 : 1,
                    transition: 'all 150ms ease',
                  }}
                >
                  {completing ? 'Cleaning up…' : 'Done'}
                </button>
              )}
            </div>
          </div>
        ) : (
          /* ── Zero worktreeEntries: direct completion path ── */
          <div style={{ marginBottom: 24 }}>
            <div
              style={{
                padding: 16,
                borderRadius: 16,
                background: C.surface,
                border: `1px solid ${C.border}`,
                textAlign: 'center',
              }}
            >
              <p style={{ fontSize: 13, color: C.textSecondary, margin: 0, marginBottom: 12 }}>
                No file changes to review
              </p>
              <button
                type="button"
                onClick={handleDirectComplete}
                style={{
                  padding: '8px 20px',
                  borderRadius: 12,
                  background: icon.gradient,
                  border: 'none',
                  color: '#fff',
                  fontSize: 13,
                  fontWeight: 600,
                  cursor: 'pointer',
                  fontFamily: 'Inter, sans-serif',
                  boxShadow: '0 8px 24px rgba(109,94,252,0.28)',
                  transition: 'all 150ms ease',
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.filter = 'brightness(1.1)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.filter = 'brightness(1)';
                }}
              >
                Complete
              </button>
            </div>
          </div>
        )}
      </div>
    </ScrollArea>
  );
}

import { useEffect, useState, useCallback } from 'react';
import { C } from '@/lib/theme';
import { sanitizeShikiHtml } from '@/lib/sanitize';
import { useUIStore } from '@/stores/uiStore';
import { useFileExplorer, type TreeNode } from '@/hooks/useFileExplorer';
import { commands } from '@/bindings';
import type { FileContent } from '@/bindings';

/* ── Shiki lazy loader ────────────────────────────────── */

type Highlighter = {
  codeToHtml: (code: string, opts: { lang: string; theme: string }) => string;
  getLoadedLanguages: () => string[];
  loadLanguage: (...langs: string[]) => Promise<void>;
};

// Core languages loaded eagerly — others loaded on demand
const CORE_LANGS = ['typescript', 'javascript', 'rust', 'json', 'bash', 'markdown'] as const;
const EXTRA_LANGS = [
  'python', 'yaml', 'toml', 'html', 'css', 'sql', 'go',
  'java', 'c', 'cpp', 'ruby', 'swift', 'kotlin', 'vue',
  'svelte', 'graphql', 'dockerfile', 'scss',
] as const;

let shikiHighlighterPromise: Promise<Highlighter> | null = null;

async function getHighlighter(): Promise<Highlighter> {
  if (!shikiHighlighterPromise) {
    shikiHighlighterPromise = import('shiki').then(({ createHighlighter }) =>
      createHighlighter({
        themes: ['github-dark-default'],
        langs: [...CORE_LANGS],
      })
    ) as Promise<Highlighter>;
  }
  return shikiHighlighterPromise;
}

/** Load a language on demand if not already loaded */
async function ensureLanguage(highlighter: Highlighter, lang: string): Promise<string> {
  const loaded = highlighter.getLoadedLanguages();
  if (loaded.includes(lang)) return lang;
  // Check if it's a known language we can load
  if ((EXTRA_LANGS as readonly string[]).includes(lang)) {
    try {
      await highlighter.loadLanguage(lang as never);
      return lang;
    } catch {
      return 'text';
    }
  }
  return 'text';
}

/* ── File icon helper ─────────────────────────────────── */

function fileIcon(isDir: boolean, ext: string): string {
  if (isDir) return '📁';
  const map: Record<string, string> = {
    rs: '🦀', ts: '🔷', tsx: '🔷', js: '🟨', jsx: '🟨',
    py: '🐍', json: '📋', md: '📝', toml: '⚙️', yaml: '⚙️', yml: '⚙️',
    html: '🌐', css: '🎨', scss: '🎨', svg: '🖼️', png: '🖼️', jpg: '🖼️',
  };
  return map[ext.toLowerCase()] ?? '📄';
}

/* ── Tree Item Component ──────────────────────────────── */

function TreeItem({
  node,
  depth,
  selectedFile,
  onToggleDir,
  onSelectFile,
}: {
  node: TreeNode;
  depth: number;
  selectedFile: string | null;
  onToggleDir: (path: string) => void;
  onSelectFile: (path: string) => void;
}) {
  const isSelected = node.entry.path === selectedFile;

  return (
    <>
      <div
        className="flex items-center gap-1.5 py-1 px-2 cursor-pointer transition-colors text-xs"
        style={{
          paddingLeft: depth * 16 + 8,
          background: isSelected ? C.accentSoft : 'transparent',
          color: isSelected ? C.accentText : C.textPrimary,
        }}
        onClick={() => {
          if (node.entry.is_dir) onToggleDir(node.entry.path);
          else onSelectFile(node.entry.path);
        }}
        onMouseEnter={(e) => {
          if (!isSelected) (e.currentTarget.style.background = C.surfaceHover);
        }}
        onMouseLeave={(e) => {
          if (!isSelected) (e.currentTarget.style.background = 'transparent');
        }}
      >
        {node.entry.is_dir && (
          <span
            className="text-[9px] flex-shrink-0 transition-transform"
            style={{
              color: C.textMuted,
              transform: node.expanded ? 'rotate(90deg)' : 'rotate(0deg)',
            }}
          >
            ▶
          </span>
        )}
        {!node.entry.is_dir && <span className="w-[9px] flex-shrink-0" />}
        <span className="flex-shrink-0 text-[12px]">{fileIcon(node.entry.is_dir, node.entry.extension)}</span>
        <span className="truncate font-mono">{node.entry.name}</span>
        {!node.entry.is_dir && node.entry.size > 0 && (
          <span className="ml-auto text-[10px] flex-shrink-0" style={{ color: C.textMuted }}>
            {node.entry.size > 1024
              ? `${(node.entry.size / 1024).toFixed(0)}KB`
              : `${node.entry.size}B`}
          </span>
        )}
      </div>
      {node.expanded && node.children?.map((child) => (
        <TreeItem
          key={child.entry.path}
          node={child}
          depth={depth + 1}
          selectedFile={selectedFile}
          onToggleDir={onToggleDir}
          onSelectFile={onSelectFile}
        />
      ))}
    </>
  );
}

/* ── Code Panel with Shiki ────────────────────────────── */

function CodePanel({
  fileContent,
  filePath,
  editing,
  projectDir,
  onFileSaved,
}: {
  fileContent: FileContent | null;
  filePath: string | null;
  editing: boolean;
  projectDir: string;
  onFileSaved: () => void;
}) {
  const [highlightedHtml, setHighlightedHtml] = useState<string>('');
  const [editBuffer, setEditBuffer] = useState<string>('');
  const [saving, setSaving] = useState(false);
  const [saveMsg, setSaveMsg] = useState<string | null>(null);
  const [hasChanges, setHasChanges] = useState(false);

  // Sync edit buffer when file content changes or editing toggled
  useEffect(() => {
    if (fileContent && fileContent.language !== 'binary') {
      setEditBuffer(fileContent.content);
      setHasChanges(false);
      setSaveMsg(null);
    }
  }, [fileContent]);

  useEffect(() => {
    if (!editing || !fileContent || fileContent.language === 'binary' || !fileContent.content) {
      setHighlightedHtml('');
      return;
    }

    let cancelled = false;

    getHighlighter().then(async (highlighter) => {
      if (cancelled) return;
      try {
        const lang = await ensureLanguage(highlighter, fileContent.language);
        const html = highlighter.codeToHtml(fileContent.content, {
          lang,
          theme: 'github-dark-default',
        });
        if (!cancelled) setHighlightedHtml(html);
      } catch { // expected: language may not be loaded in shiki
        if (!cancelled) setHighlightedHtml('');
      }
    });

    return () => { cancelled = true; };
  }, [fileContent, editing]);

  const handleSave = useCallback(async () => {
    if (!filePath || saving) return;
    setSaving(true);
    setSaveMsg(null);
    try {
      const result = await commands.writeFile(projectDir, filePath, editBuffer);
      if (result.status === 'ok') {
        setSaveMsg('Saved');
        setHasChanges(false);
        onFileSaved();
        setTimeout(() => setSaveMsg(null), 2000);
      } else {
        setSaveMsg(`Error: ${result.error}`);
      }
    } catch (e) {
      setSaveMsg(`Error: ${e}`);
    } finally {
      setSaving(false);
    }
  }, [filePath, editBuffer, projectDir, saving, onFileSaved]);

  if (!filePath) {
    return (
      <div className="flex-1 flex items-center justify-center" style={{ background: C.bg }}>
        <div className="text-center">
          <div className="text-2xl mb-2">◈</div>
          <div className="text-sm" style={{ color: C.textMuted }}>
            Select a file to view
          </div>
        </div>
      </div>
    );
  }

  if (!fileContent) {
    return (
      <div className="flex-1 flex items-center justify-center" style={{ background: C.bg }}>
        <span className="text-xs" style={{ color: C.textMuted }}>Loading...</span>
      </div>
    );
  }

  if (fileContent.language === 'binary') {
    return (
      <div className="flex-1 flex items-center justify-center" style={{ background: C.bg }}>
        <span className="text-xs" style={{ color: C.textMuted }}>Binary file — cannot display</span>
      </div>
    );
  }

  return (
    <div className="flex-1 flex flex-col overflow-hidden" style={{ background: C.bg }}>
      {/* File header */}
      <div
        className="flex items-center gap-2 px-4 py-2 border-b flex-shrink-0"
        style={{ borderColor: C.border, background: C.panel }}
      >
        <span className="text-xs font-mono" style={{ color: C.textPrimary }}>
          {filePath}
        </span>
        {hasChanges && (
          <span className="w-2 h-2 rounded-full flex-shrink-0" style={{ background: C.amber }} />
        )}
        <div className="flex-1" />
        {editing && hasChanges && (
          <button
            onClick={handleSave}
            disabled={saving}
            className="text-[10px] px-2.5 py-1 rounded-md font-semibold transition-all"
            style={{
              background: C.accent,
              color: '#fff',
              opacity: saving ? 0.5 : 1,
            }}
          >
            {saving ? 'Saving...' : 'Save'}
          </button>
        )}
        {saveMsg && (
          <span
            className="text-[10px] px-1.5 py-0.5 rounded font-medium"
            style={{
              color: saveMsg.startsWith('Error') ? C.red : C.green,
              background: saveMsg.startsWith('Error') ? C.redBg : C.greenBg,
            }}
          >
            {saveMsg}
          </span>
        )}
        {editing && (
          <span
            className="text-[10px] px-1.5 py-0.5 rounded-full font-medium"
            style={{ background: C.accentSoft, color: C.accentText }}
          >
            editing
          </span>
        )}
        <span className="text-[10px] px-1.5 py-0.5 rounded" style={{ color: C.textMuted, background: C.surface }}>
          {fileContent.language}
        </span>
        <span className="text-[10px]" style={{ color: C.textMuted }}>
          {fileContent.size > 1024
            ? `${(fileContent.size / 1024).toFixed(1)}KB`
            : `${fileContent.size}B`}
        </span>
        {fileContent.truncated && (
          <span
            className="text-[10px] px-1.5 py-0.5 rounded-full"
            style={{ background: C.amberBg, color: C.amber }}
          >
            truncated
          </span>
        )}
      </div>

      {/* Code content */}
      <div className="flex-1 overflow-auto">
        {editing ? (
          <textarea
            value={editBuffer}
            onChange={(e) => {
              setEditBuffer(e.target.value);
              setHasChanges(e.target.value !== fileContent.content);
            }}
            onKeyDown={(e) => {
              // Cmd/Ctrl+S to save
              if ((e.metaKey || e.ctrlKey) && e.key === 's') {
                e.preventDefault();
                handleSave();
              }
              // Tab inserts 2 spaces
              if (e.key === 'Tab') {
                e.preventDefault();
                const start = e.currentTarget.selectionStart;
                const end = e.currentTarget.selectionEnd;
                const val = editBuffer;
                const newVal = val.substring(0, start) + '  ' + val.substring(end);
                setEditBuffer(newVal);
                setHasChanges(newVal !== fileContent.content);
                requestAnimationFrame(() => {
                  e.currentTarget.selectionStart = e.currentTarget.selectionEnd = start + 2;
                });
              }
            }}
            className="w-full h-full text-[12px] leading-[20px] p-4 resize-none"
            style={{
              fontFamily: "'JetBrains Mono', 'Fira Code', monospace",
              background: 'transparent',
              color: C.textPrimary,
              outline: 'none',
              border: 'none',
              tabSize: 2,
            }}
            spellCheck={false}
          />
        ) : highlightedHtml ? (
          <div
            className="shiki-container text-[12px] leading-[20px] p-4"
            style={{ fontFamily: "'JetBrains Mono', 'Fira Code', monospace" }}
            dangerouslySetInnerHTML={{ __html: sanitizeShikiHtml(highlightedHtml) }}
          />
        ) : (
          <pre
            className="text-[12px] leading-[20px] p-4 font-mono whitespace-pre"
            style={{ color: C.textPrimary, margin: 0 }}
          >
            {fileContent.content}
          </pre>
        )}
      </div>
    </div>
  );
}

/* ── Main CodeView ────────────────────────────────────── */

export function CodeView() {
  const projectDir = useUIStore((s) => s.projectDir);
  const developerMode = useUIStore((s) => s.developerMode);
  const {
    rootEntries, selectedFile, fileContent, loading, error,
    loadRoot, toggleDir, selectFile,
  } = useFileExplorer(projectDir);

  const handleFileSaved = useCallback(() => {
    // Re-read the file after save to sync content
    if (selectedFile) selectFile(selectedFile);
  }, [selectedFile, selectFile]);

  useEffect(() => {
    loadRoot();
  }, [loadRoot]);

  if (!projectDir) {
    return (
      <div className="flex-1 flex items-center justify-center" style={{ background: C.bg }}>
        <div className="text-center">
          <div className="text-2xl mb-2">◈</div>
          <div className="text-sm font-medium" style={{ color: C.textSecondary }}>
            No project directory selected
          </div>
          <div className="text-xs mt-1" style={{ color: C.textMuted }}>
            Launch a session to browse code
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex-1 flex overflow-hidden" style={{ background: C.bg }}>
      {/* File tree sidebar */}
      <div
        className="flex flex-col overflow-hidden border-r flex-shrink-0"
        style={{ width: 260, borderColor: C.border, background: C.panel }}
      >
        {/* Tree header */}
        <div
          className="flex items-center gap-2 px-3 py-2 border-b flex-shrink-0"
          style={{ borderColor: C.border }}
        >
          <span className="text-xs font-semibold truncate" style={{ color: C.textPrimary }}>
            {projectDir.split('/').pop()}
          </span>
          <div className="flex-1" />
          <button
            onClick={loadRoot}
            disabled={loading}
            className="text-[10px] px-1.5 py-0.5 rounded transition-colors"
            style={{ color: C.textMuted }}
          >
            {loading ? '⟳' : '↻'}
          </button>
        </div>

        {/* Error */}
        {error && (
          <div className="px-3 py-1 text-[10px]" style={{ color: C.red }}>
            {error}
          </div>
        )}

        {/* Tree */}
        <div className="flex-1 overflow-y-auto py-1">
          {rootEntries.map((node) => (
            <TreeItem
              key={node.entry.path}
              node={node}
              depth={0}
              selectedFile={selectedFile}
              onToggleDir={toggleDir}
              onSelectFile={selectFile}
            />
          ))}
          {rootEntries.length === 0 && !loading && (
            <div className="px-3 py-4 text-xs text-center" style={{ color: C.textMuted }}>
              Empty directory
            </div>
          )}
        </div>
      </div>

      {/* Code panel */}
      <CodePanel
        fileContent={fileContent}
        filePath={selectedFile}
        editing={developerMode}
        projectDir={projectDir}
        onFileSaved={handleFileSaved}
      />
    </div>
  );
}

