/* ── Helpers ───────────────────────────────────────────── */

function formatElapsed(startedAt: number | null): string {
  if (!startedAt) return '--';
  const s = Math.floor((Date.now() - startedAt) / 1000);
  if (s < 60) return `${s}s`;
  const m = Math.floor(s / 60);
  return `${m}m ${s % 60}s`;
}

