                    background: C.panel,
                    border: `1px solid ${C.borderStrong}`,
                    borderRadius: 12,
                    overflow: 'hidden',
                    zIndex: 10,
                    boxShadow: '0 8px 32px rgba(0,0,0,0.5)',
                  }}
                >
                  {otherAgents.map((agent) => {
                    const info = AGENTS[agent];
                    return (
                      <button
                        key={agent}
                        type="button"
                        onClick={() => handleSwitchAgent(agent)}
                        style={{
                          width: '100%',
                          display: 'flex',
